mapper.select:
SELECT bc.id AS id, bc.company_phone As companyPhone, bc.company_name AS text, bc.company_name As companyName, bc.company_type As companyType, bc.contact_phone As contactPhone, bc.contact_name As contactName, bc.address As address, bc.on_line_flg As onLineFlg FROM t_bs_company bc WHERE bc.enable_flg = true and bc.credit_rating = 'W' AND bc.enterprise_id = #{enterpriseId}
AND bc.company_name LIKE CONCAT('%',#{companyName},'%')
AND bc.total_credit_amount > 0
